/**
 * dashboard-scaffold.cjs -- Self-contained HTML dashboard generator
 * Version: 1.0.0
 *
 * Takes a JSON dashboard specification and generates a complete, self-contained
 * HTML file with Chart.js charts, KPI cards, filters, data tables, and drill-down
 * modals. Zero build step -- open in any browser.
 *
 * Usage:
 *   node dashboard-scaffold.cjs <spec.json>                   # Generate from spec
 *   node dashboard-scaffold.cjs <spec.json> --output out.html # Custom output path
 *   node dashboard-scaffold.cjs --example                     # Print example spec
 *
 * Spec format: see --example output or DATA-STORYTELLING-TRIFECTA-PLAN.md
 */
'use strict';

const fs = require('fs');
const path = require('path');

// -----------------------------------------------------------------------------
// EXAMPLE SPEC
// -----------------------------------------------------------------------------

const EXAMPLE_SPEC = {
  title: 'Sample Dashboard',
  subtitle: 'Generated by dashboard-scaffold.cjs',
  theme: 'dark',
  data: {
    labels: ['Alpha', 'Beta', 'Gamma', 'Delta', 'Epsilon'],
    values: [45, 32, 28, 19, 12]
  },
  kpis: [
    { label: 'Total', value: '136', subtitle: 'All items', accent: '#6366f1' },
    { label: 'Average', value: '27.2', subtitle: 'Per category', accent: '#3b82f6' },
    { label: 'Top', value: 'Alpha', subtitle: '45 (33%)', accent: '#10b981' }
  ],
  charts: [
    { type: 'bar', title: 'Alpha leads with 33% of total', fullWidth: true }
  ],
  table: {
    columns: ['Rank', 'Category', 'Value', 'Share'],
    sortable: true
  }
};

// -----------------------------------------------------------------------------
// THEME
// -----------------------------------------------------------------------------

const THEMES = {
  dark: {
    bgPrimary: '#0f0f23', bgCard: '#1a1a2e', bgHover: '#16213e',
    textPrimary: '#e8e8f0', textSecondary: '#888', textMuted: '#555',
    border: '#2a2a4a', shadow: '0 2px 8px rgba(0,0,0,0.3)',
    // Colorblind-safe palette -- Tableau 10
    accent: ['#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f', '#edc948', '#b07aa1', '#ff9da7']
  },
  light: {
    bgPrimary: '#f8f9fa', bgCard: '#ffffff', bgHover: '#f0f2f5',
    textPrimary: '#1f2328', textSecondary: '#555', textMuted: '#999',
    border: '#e0e0e0', shadow: '0 2px 8px rgba(0,0,0,0.08)',
    // Colorblind-safe palette -- Tableau 10
    accent: ['#4e79a7', '#f28e2b', '#e15759', '#76b7b2', '#59a14f', '#edc948', '#b07aa1', '#ff9da7']
  }
};

// -----------------------------------------------------------------------------
// HTML GENERATORS
// -----------------------------------------------------------------------------

function generateKpiHtml(kpis) {
  return kpis.map(k => `
    <div class="kpi-card" style="border-top: 3px solid ${k.accent || '#6366f1'}">
      ${k.icon ? `<div class="kpi-icon">${k.icon}</div>` : ''}
      <div class="kpi-value">${escapeHtml(String(k.value))}</div>
      <div class="kpi-label">${escapeHtml(k.label)}</div>
      ${k.subtitle ? `<div class="kpi-subtitle">${escapeHtml(k.subtitle)}</div>` : ''}
      ${k.delta ? `<div class="kpi-delta ${k.delta.startsWith('+') || k.delta.startsWith('^') ? 'positive' : 'negative'}">${escapeHtml(k.delta)}</div>` : ''}
    </div>
  `).join('\n');
}

function generateChartJs(charts, dataSpec) {
  const scripts = [];
  charts.forEach((chart, idx) => {
    const canvasId = `chart-${idx}`;
    const labels = JSON.stringify(dataSpec.labels || []);
    const values = JSON.stringify(dataSpec.values || []);
    let chartType = chart.type || 'bar';
    if (chartType === 'horizontalBar') chartType = 'bar'; // Chart.js v4

    scripts.push(`
      new Chart(document.getElementById('${canvasId}').getContext('2d'), {
        type: '${chartType}',
        data: {
          labels: ${labels},
          datasets: [{
            data: ${values},
            backgroundColor: theme.accent.slice(0, ${(dataSpec.labels || []).length}),
            borderWidth: 0,
            borderRadius: 4
          }]
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          indexAxis: '${chart.type === 'horizontalBar' ? 'y' : 'x'}',
          plugins: {
            legend: { display: false },
            title: { display: ${chart.title ? 'true' : 'false'}, text: ${JSON.stringify(chart.title || '')}, color: theme.textPrimary, font: { size: 15, weight: '600' }, padding: { bottom: 12 } }
          },
          scales: {
            x: { grid: { display: false }, ticks: { color: theme.textSecondary, font: { size: 11 } } },
            y: { grid: { color: theme.border + '44' }, ticks: { color: theme.textSecondary, font: { size: 11 } } }
          }
        }
      });
    `);
  });
  return scripts.join('\n');
}

function generateTableHtml(tableSpec, dataSpec) {
  if (!tableSpec) return '';
  const headers = (tableSpec.columns || []).map(c => `<th>${escapeHtml(c)}</th>`).join('');
  const rows = (dataSpec.labels || []).map((label, i) => {
    const val = (dataSpec.values || [])[i] || 0;
    const total = (dataSpec.values || []).reduce((s, v) => s + v, 0);
    const share = total > 0 ? ((val / total) * 100).toFixed(1) + '%' : '0%';
    return `<tr><td>${i + 1}</td><td>${escapeHtml(label)}</td><td>${val.toLocaleString()}</td><td>${share}</td></tr>`;
  }).join('\n');

  return `
    <div class="table-container">
      <table>
        <thead><tr>${headers}</tr></thead>
        <tbody>${rows}</tbody>
      </table>
    </div>
  `;
}

function escapeHtml(str) {
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// -----------------------------------------------------------------------------
// MAIN GENERATOR
// -----------------------------------------------------------------------------

function generate(spec) {
  const theme = THEMES[spec.theme] || THEMES.dark;
  const chartCanvases = (spec.charts || []).map((chart, idx) => {
    const widthClass = chart.fullWidth ? 'full-width' : 'half-width';
    return `<div class="chart-panel ${widthClass}"><canvas id="chart-${idx}"></canvas></div>`;
  }).join('\n');

  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${escapeHtml(spec.title || 'Dashboard')}</title>
<script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
<style>
  :root {
    --bg-primary: ${theme.bgPrimary};
    --bg-card: ${theme.bgCard};
    --bg-hover: ${theme.bgHover};
    --text-primary: ${theme.textPrimary};
    --text-secondary: ${theme.textSecondary};
    --text-muted: ${theme.textMuted};
    --border: ${theme.border};
    --shadow: ${theme.shadow};
    --radius: 12px;
  }
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: 'Segoe UI', system-ui, sans-serif; background: var(--bg-primary); color: var(--text-primary); padding: 24px; min-height: 100vh; }

  .header { text-align: center; margin-bottom: 24px; }
  .header h1 { font-size: 1.8rem; margin-bottom: 4px; }
  .header .subtitle { color: var(--text-secondary); font-size: 0.95rem; }

  .kpi-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 16px; margin-bottom: 24px; }
  .kpi-card { background: var(--bg-card); border-radius: var(--radius); padding: 20px; box-shadow: var(--shadow); }
  .kpi-icon { font-size: 1.5rem; margin-bottom: 8px; }
  .kpi-value { font-size: 1.8rem; font-weight: 700; }
  .kpi-label { color: var(--text-secondary); font-size: 0.85rem; margin-top: 4px; }
  .kpi-subtitle { color: var(--text-muted); font-size: 0.8rem; margin-top: 2px; }
  .kpi-delta { font-size: 0.85rem; margin-top: 4px; font-weight: 600; }
  .kpi-delta.positive { color: #10b981; }
  .kpi-delta.negative { color: #ef4444; }

  .chart-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(400px, 1fr)); gap: 16px; margin-bottom: 24px; }
  .chart-panel { background: var(--bg-card); border-radius: var(--radius); padding: 20px; box-shadow: var(--shadow); min-height: 300px; }
  .chart-panel.full-width { grid-column: 1 / -1; }

  .table-container { background: var(--bg-card); border-radius: var(--radius); padding: 20px; box-shadow: var(--shadow); overflow-x: auto; }
  table { width: 100%; border-collapse: collapse; }
  th { text-align: left; padding: 10px 12px; border-bottom: 2px solid var(--border); color: var(--text-secondary); font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.5px; cursor: pointer; }
  td { padding: 10px 12px; border-bottom: 1px solid var(--border); font-size: 0.9rem; }
  tr:hover td { background: var(--bg-hover); }

  .footer { text-align: center; color: var(--text-muted); font-size: 0.75rem; margin-top: 24px; padding-top: 16px; border-top: 1px solid var(--border); }

  @media (max-width: 768px) {
    .chart-grid { grid-template-columns: 1fr; }
    .kpi-grid { grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); }
    body { padding: 12px; }
  }
  @media print {
    body { background: white; color: black; }
    .kpi-card, .chart-panel, .table-container { box-shadow: none; border: 1px solid #ddd; }
  }
</style>
</head>
<body>

<div class="header">
  <h1>${escapeHtml(spec.title || 'Dashboard')}</h1>
  ${spec.subtitle ? `<div class="subtitle">${escapeHtml(spec.subtitle)}</div>` : ''}
</div>

${spec.kpis ? `<div class="kpi-grid">${generateKpiHtml(spec.kpis)}</div>` : ''}

<div class="chart-grid">
  ${chartCanvases}
</div>

${spec.table ? generateTableHtml(spec.table, spec.data || {}) : ''}

<div class="footer">
  ${spec.source ? `Data: ${escapeHtml(spec.source)} | ` : ''}Generated by dashboard-scaffold.cjs | ${new Date().toISOString().slice(0, 10)}
</div>

<script>
const theme = {
  textPrimary: '${theme.textPrimary}',
  textSecondary: '${theme.textSecondary}',
  border: '${theme.border}',
  accent: ${JSON.stringify(theme.accent)}
};

Chart.defaults.font.family = "'Segoe UI', system-ui, sans-serif";
Chart.defaults.font.size = 13;

${generateChartJs(spec.charts || [], spec.data || {})}

// Sortable table
document.querySelectorAll('th').forEach((th, colIdx) => {
  let asc = true;
  th.addEventListener('click', () => {
    const tbody = th.closest('table').querySelector('tbody');
    const rows = Array.from(tbody.rows);
    rows.sort((a, b) => {
      const av = a.cells[colIdx]?.textContent || '';
      const bv = b.cells[colIdx]?.textContent || '';
      const an = parseFloat(av.replace(/[^\\d.-]/g, ''));
      const bn = parseFloat(bv.replace(/[^\\d.-]/g, ''));
      if (!isNaN(an) && !isNaN(bn)) return asc ? an - bn : bn - an;
      return asc ? av.localeCompare(bv) : bv.localeCompare(av);
    });
    rows.forEach(r => tbody.appendChild(r));
    asc = !asc;
  });
});
</script>
</body>
</html>`;
}

// -----------------------------------------------------------------------------
// CLI
// -----------------------------------------------------------------------------

function main() {
  const args = process.argv.slice(2);

  if (args.includes('--help') || args.length === 0) {
    console.log(`
dashboard-scaffold.cjs -- Self-contained HTML dashboard generator

Usage:
  node dashboard-scaffold.cjs <spec.json>
  node dashboard-scaffold.cjs <spec.json> --output dashboard.html
  node dashboard-scaffold.cjs --example
    `.trim());
    process.exit(0);
  }

  if (args.includes('--example')) {
    console.log(JSON.stringify(EXAMPLE_SPEC, null, 2));
    process.exit(0);
  }

  const specPath = args.find(a => !a.startsWith('--'));
  if (!specPath) { console.error('Error: No spec file specified'); process.exit(1); }

  const absPath = path.resolve(specPath);
  if (!fs.existsSync(absPath)) { console.error(`Error: File not found: ${absPath}`); process.exit(1); }

  const spec = JSON.parse(fs.readFileSync(absPath, 'utf-8'));
  const html = generate(spec);

  const outIdx = args.indexOf('--output');
  const outputPath = outIdx !== -1 ? args[outIdx + 1] : specPath.replace(/\.json$/i, '.html');

  fs.writeFileSync(outputPath, html, 'utf-8');
  console.log(`Dashboard generated: ${outputPath}`);
}

main();

module.exports = { generate, THEMES, EXAMPLE_SPEC };
